body.text:
# Basic pipeline structure:
input {
  file {
    path => "/var/log/auth.log"
    start_position => "beginning"
    sincedb_path => "/dev/null"  # Re-read from start
  }
}

filter {
  # Parse, transform, enrich here
}

output {
  elasticsearch {
    hosts => ["localhost:9200"]
    index => "ssh-auth-logs-%{+YYYY.MM.dd}"
  }
}

# Read local log files:
input {
  file { path => "/var/log/*.log" }
}

# Receive from Filebeat agents (most common in production):
input {
  beats { port => 5044 }
}

# Receive syslog from network devices:
input {
  syslog { port => 514 }  # UDP by default
}

# TCP input (custom log sources):
input {
  tcp {
    port => 5000
    codec => json_lines
  }
}

# grok parses unstructured text using named patterns:
filter {
  grok {
    match => {
      "message" => "%{SYSLOGTIMESTAMP:timestamp} %{HOSTNAME:hostname} sshd\[%{NUMBER:pid}\]: Failed password for %{USERNAME:username} from %{IP:src_ip} port %{NUMBER:src_port}"
    }
  }
}

filter {
  grok {
    # ... parse SSH failed login as above ...
  }

  # Add geographic location to every source IP:
  geoip {
    source => "src_ip"
    # Adds: src_ip.geo.country_name, city_name, location
  }

  # Resolve IP to hostname:
  dns {
    reverse => ["src_ip"]
    action => "replace"
  }

  # Rename fields to ECS standard:
  mutate {
    rename => {
      "src_ip"   => "source.ip"
      "username" => "user.name"
    }
  }
}
